INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000000', 'acc06b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why coordinate geometry drives advanced surveying</h3><p>SRVY 2341 builds on the traverse, leveling, and measurement skills you developed earlier, but nearly every advanced computation — a curve PI, an earthwork cross-section, a state plane reduction — ultimately reduces to operations on <strong>rectangular coordinates</strong> (N, E). This course assumes you can move fluently between <em>polar</em> data (a distance and a direction) and <em>rectangular</em> data (a northing and an easting). The two recurring operations are the <strong>forward</strong> computation (given a point, a direction, and a distance, find the next point) and the <strong>inverse</strong> computation (given two points, find the distance and direction between them).</p><p>In Texas practice, directions are usually carried as <strong>azimuths from north</strong> or as <strong>quadrant bearings</strong>. Internally, software and your calculator work cleanest in azimuths because the trigonometry is unambiguous over a full 360 degrees.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000001', 'acc06b01-0000-0000-0000-000000000001', 'equation', '{"latex":"\\Delta N = L\\cos(Az), \\quad \\Delta E = L\\sin(Az)","label":"Forward computation (latitude and departure)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000002', 'acc06b01-0000-0000-0000-000000000001', 'equation', '{"latex":"L = \\sqrt{\\Delta N^2 + \\Delta E^2}, \\quad Az = \\operatorname{atan2}(\\Delta E, \\Delta N)","label":"Inverse computation","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000003', 'acc06b01-0000-0000-0000-000000000001', 'table', '{"headers":["Operation","Given","Find","Key relationship"],"rows":[["Forward","Point, Az, L","Next point (N,E)","N2 = N1 + L cos Az"],["Inverse","Two points","L and Az","Az = atan2(dE, dN)"],["Area","Closed polygon","Area","Coordinate / shoelace method"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000004', 'acc06b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Area by coordinates</h3><p>The <strong>coordinate method</strong> (equivalently the shoelace or DMD method) gives the exact area of any closed, non-self-intersecting polygon directly from its corner coordinates. It is the engine behind parcel acreage, earthwork end areas, and pond volumes. Order the vertices consistently (clockwise or counter-clockwise) and the magnitude of the result is the area regardless of direction; the sign only tells you the traverse sense.</p><ul><li>Always close the polygon back to the first point.</li><li>Use full-precision coordinates — rounding intermediate values corrupts the doubled sum.</li><li>Divide acres by 43,560 sq ft only at the very end.</li></ul>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000005', 'acc06b01-0000-0000-0000-000000000001', 'equation', '{"latex":"A = \\tfrac{1}{2}\\left|\\sum_{i=1}^{n} \\left(E_i\\,N_{i+1} - E_{i+1}\\,N_i\\right)\\right|","label":"Area by coordinates (shoelace)","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000006', 'acc06b01-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: many Texas records carry directions as quadrant bearings tied to a specific basis (e.g., GLO, prior deed call, or a grid bearing on a named SPCS zone). Always state your basis of bearing on the plat; mixing a grid azimuth with a geodetic or astronomic bearing is a common and serious error."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0001-0000-0000-000000000007', 'acc06b01-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Forward and inverse computations are the two operations behind all COGO.","Carry directions as azimuths internally; convert to bearings for the deed.","Area by coordinates is exact and is reused for cross-sections and parcels."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000000', 'acc06b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The simple horizontal curve</h3><p>A <strong>simple curve</strong> is a single circular arc of radius R that smoothly connects two straight tangent lines. The tangents, if extended, meet at the <strong>point of intersection (PI)</strong>, and the angle between them is the <strong>intersection (deflection) angle I</strong> — equal to the central angle of the arc. The curve begins at the <strong>point of curvature (PC)</strong>, where it leaves the back tangent, and ends at the <strong>point of tangency (PT)</strong>, where it rejoins the forward tangent. Because the radius is perpendicular to the tangent at the PC and PT, the geometry is fully determined by just two quantities: <strong>R</strong> and <strong>I</strong>.</p><p>Everything else — tangent distance, curve length, external distance, middle ordinate, and long chord — follows from R and I by simple right-triangle trigonometry on the half-angle I/2.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000001', 'acc06b02-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Geometry of a simple circular curve and its elements."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000002', 'acc06b02-0000-0000-0000-000000000001', 'equation', '{"latex":"T = R\\tan\\!\\left(\\tfrac{I}{2}\\right), \\quad L = \\frac{\\pi R I^{\\circ}}{180} = R\\,I_{\\text{rad}}","label":"Tangent and arc length","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000003', 'acc06b02-0000-0000-0000-000000000001', 'equation', '{"latex":"E = R\\!\\left(\\sec\\tfrac{I}{2}-1\\right), \\quad M = R\\!\\left(1-\\cos\\tfrac{I}{2}\\right), \\quad LC = 2R\\sin\\tfrac{I}{2}","label":"External, middle ordinate, long chord","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000004', 'acc06b02-0000-0000-0000-000000000001', 'table', '{"headers":["Element","Symbol","Formula"],"rows":[["Tangent distance","T","R tan(I/2)"],["Curve (arc) length","L","R I (I in radians)"],["External distance","E","R(sec(I/2) - 1)"],["Middle ordinate","M","R(1 - cos(I/2))"],["Long chord","LC","2 R sin(I/2)"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000005', 'acc06b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Degree of curve</h3><p>U.S. route surveying often specifies curve sharpness by <strong>degree of curve, D</strong>, rather than radius. Under the <strong>arc definition</strong> (standard for highways), D is the central angle that subtends a 100-ft <em>arc</em>; under the <strong>chord definition</strong> (traditional railroad practice), D subtends a 100-ft <em>chord</em>. A larger D means a sharper, smaller-radius curve. Arc and chord definitions agree to within a few hundredths of a foot for flat curves but diverge for sharp ones, so always state which definition governs.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000006', 'acc06b02-0000-0000-0000-000000000001', 'equation', '{"latex":"D_{\\text{arc}} = \\frac{100\\cdot 180}{\\pi R} = \\frac{5729.58}{R}","label":"Degree of curve (arc definition)","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0002-0000-0000-000000000007', 'acc06b02-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A simple curve is fully defined by R and I.","Master equations: T = R tan(I/2), L = R*I (I in radians).","Degree of curve (arc) D = 5729.58/R; larger D = sharper curve."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000000', 'acc06b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From geometry to the ground</h3><p>Designing a curve gives you R, I, T, and L; <strong>staking</strong> it requires putting points on the ground at regular stations along the arc. The first step is <strong>stationing</strong>. The PI station is known from the alignment. Because the curve departs the back tangent at the PC, you <em>subtract</em> the tangent distance from the PI station to get the PC, then add the <em>arc length</em> (not the tangent) to reach the PT.</p><ul><li><strong>PC station = PI station − T</strong></li><li><strong>PT station = PC station + L</strong></li></ul><p>A classic blunder is computing the PT as PI + T; the curve is shorter than going out to the PI and back, so this is always wrong.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000001', 'acc06b03-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{Sta}_{PC}=\\text{Sta}_{PI}-T, \\qquad \\text{Sta}_{PT}=\\text{Sta}_{PC}+L","label":"Curve stationing","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000002', 'acc06b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Deflection-angle (chord) method</h3><p>The traditional and still common field method stakes the curve from the <strong>PC</strong> by turning <strong>deflection angles</strong> from the back tangent and measuring chords to each point. The governing principle is the <em>inscribed angle theorem</em>: the deflection angle from the tangent to any point on the curve equals <strong>half</strong> the central angle subtended by the arc from the PC to that point. So the total deflection from PC to PT is exactly I/2.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000003', 'acc06b03-0000-0000-0000-000000000001', 'equation', '{"latex":"\\delta = \\frac{D}{2}\\cdot\\frac{\\ell}{100} \\;=\\; \\frac{90\\,\\ell}{\\pi R}\\ \\text{(deg)}, \\qquad c = 2R\\sin(\\delta)","label":"Deflection angle and chord to a point at arc distance L from PC","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000004', 'acc06b03-0000-0000-0000-000000000001', 'table', '{"headers":["Station","Arc from PC (ft)","Deflection angle","Note"],"rows":[["PC","0","0 deg 00''","Occupy, backsight PI/tangent"],["First even sta","sub-chord","partial","Short chord to round station"],["Interior even stas","100 each","cumulative","Full 100-ft chords"],["PT","L","I/2","Check against forward tangent"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000005', 'acc06b03-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Modern practice stakes curves by coordinates with a total station or RTK GPS — compute (N,E) of each curve point and stake by radial or RTK methods. The deflection-angle method remains the conceptual check and the exam standard, and it is the fallback when only a total station on the PC is available."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000006', 'acc06b03-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Staking a simple curve by deflection angles and chords from the PC."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0003-0000-0000-000000000007', 'acc06b03-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["PC = PI station − T; PT = PC + L (use arc length, not tangent).","Deflection to any point = half its subtended central angle; total = I/2.","Coordinate staking has largely replaced chords, but deflections remain the check."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000000', 'acc06b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Beyond the simple curve</h3><p>Terrain and design constraints often prevent a single radius from fitting an alignment. Two extensions are common. A <strong>compound curve</strong> consists of two (or more) circular arcs curving in the <em>same direction</em> but with <em>different radii</em>, joined at a <strong>point of compound curvature (PCC)</strong> where they share a common tangent. A <strong>reverse curve</strong> consists of two arcs curving in <em>opposite directions</em>, joined at a <strong>point of reverse curvature (PRC)</strong>.</p><p>Compound curves let an alignment hug variable terrain (e.g., interchange ramps). Reverse curves are useful for offset alignments but are hazardous at speed because a vehicle''s steering and superelevation must reverse instantly at the PRC.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000001', 'acc06b04-0000-0000-0000-000000000001', 'table', '{"headers":["Curve type","Junction point","Direction of arcs","Typical use"],"rows":[["Compound","PCC","Same direction, different R","Interchange ramps, variable terrain"],["Reverse","PRC","Opposite directions","Offset alignments, crossovers"],["Spiral (transition)","TS, SC, CS, ST","Gradually varying R","High-speed approach to circular arc"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000002', 'acc06b04-0000-0000-0000-000000000001', 'equation', '{"latex":"T_{\\text{total}} \\text{ found from } \\; T_1=R_1\\tan\\tfrac{I_1}{2},\\; T_2=R_2\\tan\\tfrac{I_2}{2},\\; I=I_1+I_2","label":"Compound-curve tangent components","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000003', 'acc06b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Spiral transition curves and superelevation</h3><p>On high-speed routes, jumping abruptly from a straight tangent (infinite radius) to a circular arc (finite radius R) would require an instantaneous lateral acceleration. A <strong>spiral (clothoid)</strong> inserts a transition along which the radius decreases uniformly from infinity to R, so curvature — and the lateral force a driver feels — builds gradually. The spiral also provides the length over which <strong>superelevation</strong> (the banking, e) is rotated in, counteracting centrifugal force. AASHTO design relates the superelevation rate e and side-friction factor f to design speed V and radius R.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000004', 'acc06b04-0000-0000-0000-000000000001', 'equation', '{"latex":"R_{\\min} = \\frac{V^2}{15\\,(e + f)}","label":"Minimum radius for design speed (V in mph, e and f as decimals)","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000005', 'acc06b04-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Reverse curves without an intervening tangent or spiral are discouraged for highways because superelevation cannot reverse instantaneously. Provide a tangent or compound spiral between opposing arcs so the cross-slope can be transitioned through level."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000006', 'acc06b04-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Compound vs. reverse curve geometry and junction points."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0004-0000-0000-000000000007', 'acc06b04-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Compound = same-direction arcs at a PCC; reverse = opposite-direction arcs at a PRC.","Spirals make curvature change gradual and host superelevation runoff.","Reverse curves need separation (tangent/spiral) so banking can transition safely."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0005-0000-0000-000000000000', 'acc06b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Vertical curves: parabolas, not arcs</h3><p>Where two roadway <strong>grades</strong> (g1 in, g2 out, expressed as percent or as a decimal rise/run) meet at a <strong>point of vertical intersection (PVI)</strong>, a smooth <strong>vertical curve</strong> joins them. Unlike horizontal curves, vertical curves are <strong>equal-tangent parabolas</strong>, not circular arcs, because a parabola gives a constant rate of grade change and a comfortable, constant vertical acceleration. The curve begins at the <strong>BVC</strong> (begin vertical curve, also PVC) and ends at the <strong>EVC</strong> (end vertical curve, also PVT), each L/2 from the PVI.</p><p>A <strong>crest curve</strong> occurs when the grade decreases (g1 &gt; g2), forming a hill; a <strong>sag curve</strong> occurs when the grade increases (g1 &lt; g2), forming a valley. Crest curves are usually governed by stopping sight distance; sag curves by headlight sight distance and rider comfort.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0005-0000-0000-000000000001', 'acc06b05-0000-0000-0000-000000000001', 'equation', '{"latex":"r = \\frac{g_2 - g_1}{L}\\quad\\text{(per station)}, \\qquad Y = Y_{BVC} + g_1 x + \\tfrac{r}{2}x^2","label":"Parabolic elevation (x in stations from BVC)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0005-0000-0000-000000000002', 'acc06b05-0000-0000-0000-000000000001', 'table', '{"headers":["Quantity","Symbol","Relationship"],"rows":[["Grade in / out","g1, g2","percent, signed (+ up, - down)"],["Rate of change","r","(g2 - g1)/L per station"],["BVC elevation","Y_BVC","Y_PVI - g1*(L/2)"],["Elev at offset x","Y","Y_BVC + g1*x + (r/2)*x^2"],["Turning point","x_t","-g1/r stations from BVC"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0005-0000-0000-000000000003', 'acc06b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The turning point</h3><p>The high point of a crest curve or the low point of a sag curve — the <strong>turning point</strong> — is where the instantaneous grade equals zero. Because the grade along the parabola is g1 + r*x, setting it to zero gives x_t = -g1/r stations measured from the BVC. The turning point matters for drainage (the low point of a sag fixes where inlets go) and for sight-distance checks at crests. If x_t falls outside the range 0 to L, the curve has no interior turning point and the controlling elevation is at an endpoint.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0005-0000-0000-000000000004', 'acc06b05-0000-0000-0000-000000000001', 'equation', '{"latex":"x_t = -\\frac{g_1}{r}\\;\\text{(stations from BVC)}","label":"Location of high/low point","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0005-0000-0000-000000000005', 'acc06b05-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Keep grades in percent and lengths in stations (1 station = 100 ft) so r comes out in percent-per-station. Mixing feet and stations is the most common vertical-curve blunder."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0005-0000-0000-000000000006', 'acc06b05-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Vertical curves are equal-tangent parabolas with constant rate r = (g2-g1)/L.","Elevation: Y = Y_BVC + g1*x + (r/2)x^2, x in stations from BVC.","Turning point at x = -g1/r; crest if g1>g2, sag if g1<g2."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000000', 'acc06b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Designing the length: the K value</h3><p>Choosing how <em>long</em> a vertical curve should be is a sight-distance problem. AASHTO consolidates the geometry into a single design parameter, the <strong>K value</strong>, defined as the curve length per one percent of total grade change: <strong>K = L / A</strong>, where <strong>A = |g2 − g1|</strong> is the algebraic difference of grades in percent. Each design speed has a tabulated minimum K for crest curves (stopping sight distance) and for sag curves (headlight beam distance). To design, look up K for the speed and curve type, then compute <strong>L = K·A</strong> and round up to a convenient length.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000001', 'acc06b06-0000-0000-0000-000000000001', 'equation', '{"latex":"A = |g_2 - g_1|, \\qquad K = \\frac{L}{A}, \\qquad L = K\\,A","label":"K value and design length","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000002', 'acc06b06-0000-0000-0000-000000000001', 'table', '{"headers":["Design speed (mph)","Crest K (min)","Sag K (min)"],"rows":[["30","19","37"],["45","61","79"],["60","151","136"],["70","247","181"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000003', 'acc06b06-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"K values above are representative AASHTO stopping-sight-distance figures for illustration; always design from the current AASHTO Green Book and the governing agency (TxDOT) tables, which control on Texas projects."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000004', 'acc06b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Staking the finished grade</h3><p>Field staking of a vertical curve produces <strong>grade stakes</strong>: at each even station the surveyor computes the finished-grade elevation Y = Y_BVC + g1*x + (r/2)x^2 and marks cut or fill relative to existing ground. The surveyor tabulates station, x (stations from BVC), tangent elevation, parabolic offset, and finished elevation. At the turning point the crew verifies drainage (sag) or sight clearance (crest). A useful check: the vertical offset from the tangent at the PVI equals A*L/8 (in feet when A is in percent and L in stations).</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000005', 'acc06b06-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{offset}_{PVI} = \\frac{A\\,L}{8}","label":"Mid-curve offset from tangent at the PVI","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000006', 'acc06b06-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Finished-grade elevations and the mid-curve tangent offset."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0006-0000-0000-000000000007', 'acc06b06-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["K = L/A turns sight-distance design into one lookup; L = K*A.","A = |g2 - g1| is the algebraic grade change in percent.","Stake finished elevations at even stations; mid-curve offset = A*L/8."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0007-0000-0000-000000000000', 'acc06b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The route surveying process</h3><p><strong>Route surveying</strong> is the body of work that locates and stakes a linear project — a highway, pipeline, transmission line, or rail line. It follows recognized phases: <strong>reconnaissance</strong> (broad corridor study, often from maps, LiDAR, and aerial imagery), <strong>preliminary survey</strong> (topographic mapping of candidate corridors), <strong>location survey</strong> (fixing the final centerline on the ground), and <strong>construction survey</strong> (staking the design for the contractor). At each phase the <strong>centerline</strong> — the master reference line of tangents and curves — is refined and its <strong>stationing</strong> carried forward.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0007-0000-0000-000000000001', 'acc06b07-0000-0000-0000-000000000001', 'table', '{"headers":["Phase","Goal","Typical product"],"rows":[["Reconnaissance","Identify feasible corridors","Corridor study, constraints map"],["Preliminary","Map candidate routes","Topographic / DTM mapping"],["Location","Fix final centerline","Staked centerline, alignment data"],["Construction","Stake the design","Slope stakes, blue tops, offsets"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0007-0000-0000-000000000002', 'acc06b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Coordinating horizontal and vertical alignment</h3><p>A route is a three-dimensional object: the <strong>horizontal alignment</strong> (tangents joined by horizontal curves) and the <strong>vertical alignment</strong> (grades joined by vertical curves) must be designed together. Good practice keeps the two in phase — for example, placing vertical curve crests and sags so they do not hide a horizontal curve, and avoiding a sharp horizontal curve at the bottom of a steep grade. Sight distance, drainage, and superelevation transitions all couple the two alignments.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0007-0000-0000-000000000003', 'acc06b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Stationing and station equations</h3><p>Distance along the centerline is measured by <strong>stationing</strong> (e.g., 12+50 means 1,250 ft from the project origin). When an alignment is revised and the new length differs from the old, surveyors insert a <strong>station equation</strong> at the junction (for example, \"Sta 45+20 back = Sta 45+00 ahead\") so that downstream stationing is preserved without renumbering the whole project. Station equations are documented on the plans and must be honored in all staking.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0007-0000-0000-000000000004', 'acc06b07-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"On Texas Department of Transportation (TxDOT) projects, alignments, stationing, and superelevation are delivered in standardized digital formats; the field surveyor should verify the control datum, the SPCS zone, and any combined scale factor before staking from design coordinates."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0007-0000-0000-000000000005', 'acc06b07-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Coordinated horizontal/vertical alignment on a plan-and-profile sheet."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0007-0000-0000-000000000006', 'acc06b07-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Route work flows reconnaissance to preliminary to location to construction.","Horizontal and vertical alignments are designed together in 3D.","Station equations reconcile length changes and keep stationing continuous."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0008-0000-0000-000000000000', 'acc06b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Midterm exam — scope and strategy</h3><p>The Week 8 midterm assesses the first half of SRVY 2341: coordinate geometry (forward/inverse, area), the geometry and stakeout of simple horizontal curves, compound and reverse curves, and the theory and computation of vertical curves. Expect a mix of conceptual multiple-choice questions and multi-step numeric problems. Allocate time so that a single hard problem does not consume the period.</p><p>The most reliable way to lose points is rounding too early. Carry coordinates and angles at full precision and round only the reported answer to the requested units. Wherever a problem offers an independent check, use it.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0008-0000-0000-000000000001', 'acc06b08-0000-0000-0000-000000000001', 'table', '{"headers":["Topic","Source week","Be ready to"],"rows":[["Forward/inverse, area","1","Compute (N,E), distance, azimuth, area"],["Simple curve geometry","2","Find T, L, E, M, LC from R and I"],["Curve stakeout","3","Stationing, deflection angles, chords"],["Compound/reverse","4","Solve component arcs; explain spirals"],["Vertical curves","5","Elevations and turning point"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0008-0000-0000-000000000002', 'acc06b08-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Useful self-checks: total curve deflection from PC to PT must equal I/2; PT station must equal PC + L; a vertical-curve elevation at the PVI station equals the tangent elevation plus the A*L/8 offset."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0008-0000-0000-000000000003', 'acc06b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Common pitfalls to avoid</h3><p>Watch the usual traps: computing the PT as PI + T instead of PC + L; mixing grid azimuths with quadrant bearings without converting; using I in degrees where the arc-length formula needs radians; and keeping vertical-curve grades in percent while measuring x in feet instead of stations. A quick units pass before submitting catches most of these.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0008-0000-0000-000000000004', 'acc06b08-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Midterm spans Weeks 1-7: COGO, horizontal curves, vertical curves.","Carry full precision; round only final answers.","Use built-in checks: deflection = I/2, PT = PC + L."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000000', 'acc06b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From cross-sections to volumes</h3><p>Earthwork quantities drive the cost of route projects. At each station the surveyor (or the DTM software) builds a <strong>cross-section</strong>: the existing ground profile overlaid on the design template, with the area of <strong>cut</strong> above grade and <strong>fill</strong> below grade. Each of these <strong>end areas</strong> is computed by the same coordinate (shoelace) method used for parcels, applied to the polygon between ground and template.</p><p>Volume between two adjacent cross-sections is then obtained by multiplying a representative area by the distance between them.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000001', 'acc06b09-0000-0000-0000-000000000001', 'equation', '{"latex":"V_{AEA} = \\frac{A_1 + A_2}{2}\\,\\cdot\\, d","label":"Average end area volume","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000002', 'acc06b09-0000-0000-0000-000000000001', 'equation', '{"latex":"V_{prism} = \\frac{d}{6}\\left(A_1 + 4A_m + A_2\\right)","label":"Prismoidal formula (A_m = area of the middle section)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000003', 'acc06b09-0000-0000-0000-000000000001', 'table', '{"headers":["Method","Formula","Accuracy / use"],"rows":[["Average end area","(A1+A2)/2 * d","Standard for routine quantities"],["Prismoidal","d/6 (A1 + 4Am + A2)","More accurate for warped sections"],["Prismoidal correction","AEA volume - correction","Refines AEA toward prismoidal"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000004', 'acc06b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Shrinkage, swell, and mass haul</h3><p>Computed cut and fill are <em>in-place</em> (bank) volumes. Excavated material loses volume when compacted into fill (<strong>shrinkage</strong>) or gains volume when loosened (<strong>swell</strong>); both are accounted for by a factor applied to cut. To plan the economical movement of earth, surveyors build a <strong>mass-haul diagram</strong> that plots cumulative net earthwork (cut positive, fill negative) versus station. Rising segments indicate net cut, falling segments net fill; horizontal <strong>balance lines</strong> identify reaches where cut and fill offset, and the area between the curve and a balance line measures haul (volume times distance).</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000005', 'acc06b09-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Convert cubic feet to cubic yards by dividing by 27 only at the end. End areas in square feet times station distances in feet give cubic feet; the bid item is almost always cubic yards."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000006', 'acc06b09-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Mass-haul diagram showing balance points and haul."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0009-0000-0000-000000000007', 'acc06b09-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["End areas come from the coordinate method on the ground-vs-template polygon.","Volume by average end area = (A1+A2)/2 * d; prismoidal is more accurate.","Mass-haul diagrams plan economical earth movement and balance points."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0010-0000-0000-000000000000', 'acc06b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Staking the design for the contractor</h3><p><strong>Construction staking</strong> converts plan-and-profile design into marks the contractor builds to. Because stakes at the exact design location would be destroyed by equipment, surveyors set <strong>offset stakes</strong> a known distance to the side and write the cut or fill and the offset on the stake. The crew reads the stake, applies the offset, and grades to the design.</p><p>Three staking products recur on route projects: <strong>slope stakes</strong> (where side slopes meet ground), <strong>blue tops</strong> (finished-grade hubs), and <strong>grade/offset stakes</strong> for structures and pipe.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0010-0000-0000-000000000001', 'acc06b10-0000-0000-0000-000000000001', 'table', '{"headers":["Stake type","Marks","Typical info written"],"rows":[["Offset stake","Reference point off the work","Offset distance, station, cut/fill"],["Slope stake","Catch point of side slope","Slope ratio, cut/fill to catch"],["Blue top","Finished subgrade elevation","Hub at exact grade, station"],["Grade stake","Structure/pipe invert or top","Cut/fill to design elevation"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0010-0000-0000-000000000002', 'acc06b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Slope staking and catch points</h3><p>A <strong>slope stake</strong> locates the <strong>catch point</strong> (daylight point) where a designed side slope intersects existing ground. Its offset from centerline is not fixed in advance; it depends on the slope ratio s:1 (horizontal:vertical), the depth of cut or fill, and the ground slope, so it is found by trial or by a direct formula. For level ground at a cut of depth h with side slope s:1 and half-width (template) w, the catch offset from centerline is w + s*h.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0010-0000-0000-000000000003', 'acc06b10-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{offset}_{\\text{catch}} = w + s\\,h","label":"Catch-point offset (level ground; w = template half-width, s = slope ratio, h = cut/fill depth)","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0010-0000-0000-000000000004', 'acc06b10-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Stake marking conventions: ''C'' denotes cut (excavate to reach grade), ''F'' denotes fill (add material). Always state the offset and the reference (centerline, EP, etc.). Field books and stake faces should be unambiguous to the equipment operator."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0010-0000-0000-000000000005', 'acc06b10-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Slope-stake geometry and the catch point on a cut section."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0010-0000-0000-000000000006', 'acc06b10-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Offset stakes keep references clear of the work; cut/fill and offset are written on them.","Slope stakes mark the catch point where side slope meets ground.","Catch offset on level ground = template half-width + slope ratio * depth."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0011-0000-0000-000000000000', 'acc06b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Capturing the ground surface</h3><p>A <strong>topographic survey</strong> measures enough 3D points to model the ground and its features. Methods range from <strong>total station</strong> radial shots (selective, high accuracy), to <strong>RTK GPS</strong> (fast, open-sky), to <strong>airborne and mobile LiDAR</strong> and photogrammetry (massive point density over large areas). The collected points feed a <strong>digital terrain model (DTM)</strong>, commonly stored as a <strong>triangulated irregular network (TIN)</strong> that connects points into triangular facets, with <strong>breaklines</strong> enforcing ridges, ditches, and pavement edges.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0011-0000-0000-000000000001', 'acc06b11-0000-0000-0000-000000000001', 'table', '{"headers":["Method","Strength","Limitation"],"rows":[["Total station","High accuracy, selective","Slower, line-of-sight needed"],["RTK GPS","Fast, no line-of-sight","Needs open sky, fixed solution"],["LiDAR","Dense, large area","Cost, processing, vegetation filtering"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0011-0000-0000-000000000002', 'acc06b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From surface to contours</h3><p><strong>Contours</strong> are lines of equal elevation interpolated across the TIN. Reading and drawing them correctly requires a few rules: contours never cross or split (except at a vertical cliff); they close on themselves or run off the map edge; evenly spaced contours indicate uniform slope, while closely spaced contours indicate steep ground; contours form V-shapes pointing <em>upstream</em> when they cross a stream and point <em>downhill</em> around a ridge. The <strong>contour interval</strong> — the elevation difference between adjacent contours — is chosen from the terrain relief and the map''s purpose.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0011-0000-0000-000000000003', 'acc06b11-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{slope} = \\frac{\\text{contour interval}}{\\text{horizontal spacing}}","label":"Ground slope between adjacent contours","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0011-0000-0000-000000000004', 'acc06b11-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Choose a small contour interval (e.g., 1 ft) for flat, detailed sites and a larger interval (5-20 ft) for rugged terrain or small-scale mapping. The interval must suit both the relief and the accuracy of the source data."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0011-0000-0000-000000000005', 'acc06b11-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: TIN surface and contours, including V-rules at a stream and ridge."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0011-0000-0000-000000000006', 'acc06b11-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Topo methods (total station, RTK, LiDAR) build a DTM/TIN with breaklines.","Contours never cross, close on themselves or the edge, and bunch on steep ground.","Pick the contour interval for terrain relief and map purpose."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000000', 'acc06b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>State plane coordinates in Texas</h3><p>The <strong>State Plane Coordinate System (SPCS)</strong> lets surveyors work in plane rectangular coordinates while staying tied to the national geodetic datum (<strong>NAD83</strong>). Texas is divided into <strong>five zones</strong> — North, North Central, Central, South Central, and South — each using the <strong>Lambert Conformal Conic</strong> projection, which is well suited to Texas''s predominantly east-west extent. Coordinates are published in U.S. survey feet (and meters) as <strong>northings</strong> and <strong>eastings</strong>.</p><p>Because a curved Earth is being mapped onto a flat grid, grid distances and directions differ slightly from their ground (geodetic) counterparts. Advanced surveyors must convert deliberately and document which system every value is in.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000001', 'acc06b12-0000-0000-0000-000000000001', 'table', '{"headers":["Texas SPCS zone","FIPS","Projection"],"rows":[["North","4201","Lambert Conformal Conic"],["North Central","4202","Lambert Conformal Conic"],["Central","4203","Lambert Conformal Conic"],["South Central","4204","Lambert Conformal Conic"],["South","4205","Lambert Conformal Conic"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000002', 'acc06b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Grid vs. ground: the combined scale factor</h3><p>Two effects separate grid distance from ground distance. The <strong>grid scale factor</strong> accounts for the projection (the grid is slightly too short or too long depending on position relative to the standard parallels), and the <strong>elevation (sea-level) factor</strong> reduces a ground distance to the ellipsoid. Their product is the <strong>combined scale factor (CSF)</strong>. To go from grid to ground you divide; to go from ground to grid you multiply.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000003', 'acc06b12-0000-0000-0000-000000000001', 'equation', '{"latex":"CSF = (\\text{grid scale factor}) \\times (\\text{elevation factor}), \\qquad \\text{elev factor} = \\frac{R}{R+h}","label":"Combined scale factor","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000004', 'acc06b12-0000-0000-0000-000000000001', 'equation', '{"latex":"D_{ground} = \\frac{D_{grid}}{CSF}, \\qquad D_{grid} = D_{ground}\\times CSF","label":"Grid-ground distance conversion","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000005', 'acc06b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Convergence</h3><p>Grid north (the direction of the central meridian''s projection) generally does not coincide with geodetic (true) north except on the central meridian. The angle between them is the <strong>convergence</strong> (mapping angle), gamma. To relate directions: <strong>grid azimuth = geodetic azimuth − convergence</strong>. East of the central meridian convergence is positive (grid north lies west of true north); west of it, negative. Ignoring convergence corrupts any azimuth carried between grid and geodetic systems.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000006', 'acc06b12-0000-0000-0000-000000000001', 'equation', '{"latex":"Az_{grid} = Az_{geodetic} - \\gamma","label":"Convergence relationship","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000007', 'acc06b12-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: state plane coordinates are mandatory or expected on many public projects, and Texas surveyors must clearly label whether reported bearings/distances are grid or surface (ground). A surface-adjusted, low-distortion projection or a stated CSF is common on TxDOT work; never combine grid coordinates with ground distances without converting."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0012-0000-0000-000000000008', 'acc06b12-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Texas uses Lambert Conformal Conic in five SPCS zones on NAD83.","Ground = grid / CSF; CSF = grid scale factor * elevation factor.","Convergence ties grid and geodetic azimuths: grid Az = geodetic Az - gamma."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000000', 'acc06b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Measuring from images</h3><p><strong>Photogrammetry</strong> is the science of obtaining reliable measurements and 3D models from photographs. In aerial mapping, an aircraft flies parallel strips, taking <strong>vertical photographs</strong> with substantial <strong>forward overlap</strong> (typically about 60%) and <strong>side lap</strong> (about 30%) so that every ground point appears on multiple images. Overlapping pairs are viewed <strong>stereoscopically</strong> to perceive and measure relief, and <strong>ground control points</strong> tie the model to real-world coordinates through aerotriangulation.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000001', 'acc06b13-0000-0000-0000-000000000001', 'equation', '{"latex":"S = \\frac{f}{H - h}","label":"Photo scale (f = focal length, H = flying height above datum, h = ground elevation)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000002', 'acc06b13-0000-0000-0000-000000000001', 'table', '{"headers":["Quantity","Symbol","Relationship"],"rows":[["Photo scale","S","f / (H - h)"],["Ground distance","D","photo distance / S"],["Forward overlap","-","approx 60 percent"],["Side lap","-","approx 30 percent"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000003', 'acc06b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Relief and tilt displacement</h3><p>A vertical photograph is a perspective projection, not a map. Two distortions matter: <strong>relief displacement</strong> shifts the image of an elevated point radially outward from the principal point (taller or higher points lean outward), and <strong>tilt displacement</strong> arises when the camera axis is not perfectly vertical. Orthorectification removes these to produce a true-scale <strong>orthophoto</strong>. Understanding relief displacement is also how heights of objects can be measured from a single photo.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000004', 'acc06b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Remote sensing beyond photographs</h3><p><strong>Remote sensing</strong> broadens data collection to passive multispectral imagery (for land cover and vegetation indices) and active sensors. <strong>LiDAR</strong> emits laser pulses and times their return to produce dense, accurate 3D point clouds — now a primary source for DTMs and corridor mapping. <strong>Radar (InSAR)</strong> penetrates clouds and can measure ground deformation. Each product (orthophoto, DSM/DTM, point cloud, classified imagery) has appropriate and inappropriate surveying uses; a surveyor must understand the accuracy and the control behind any derived product before relying on it.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000005', 'acc06b13-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Photogrammetric and LiDAR products are only as good as their ground control and accuracy specification. A surveyor of record must verify that derived mapping meets the project''s accuracy standard before certifying or designing from it."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000006', 'acc06b13-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Vertical photo geometry, photo scale, and relief displacement."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0013-0000-0000-000000000007', 'acc06b13-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Photogrammetry extracts measurements and 3D models from overlapping photos.","Photo scale S = f/(H - h); relief and tilt displace image points.","Remote sensing adds passive imagery and active LiDAR/radar; verify control and accuracy."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0014-0000-0000-000000000000', 'acc06b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Managing a survey project</h3><p>Technical skill is only half of professional practice; the other half is <strong>project management</strong>. A well-run survey defines a clear <strong>scope of work</strong>, a realistic <strong>schedule</strong>, and a <strong>budget</strong>, and it plans field <strong>safety</strong> and <strong>quality control</strong> from the outset. The project manager allocates crews and equipment, tracks progress against milestones, manages subconsultants (aerial, geotechnical), and maintains client communication. Scope creep, undocumented assumptions, and inadequate control are the usual causes of overruns and disputes.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0014-0000-0000-000000000001', 'acc06b14-0000-0000-0000-000000000001', 'table', '{"headers":["Management element","Question it answers"],"rows":[["Scope","What deliverables and to what standard?"],["Schedule","When must each milestone be met?"],["Budget","What labor, equipment, and subs are funded?"],["QA/QC","How is accuracy verified and documented?"],["Safety","How are field hazards controlled?"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0014-0000-0000-000000000002', 'acc06b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Standards, specifications, and deliverables</h3><p>Survey deliverables must meet a stated <strong>accuracy standard</strong> and the requirements of the contract and any governing specification. Professional and federal standards (e.g., ALTA/NSPS Land Title Surveys, NGS/FGDC positional-accuracy standards, and agency specs like TxDOT survey manuals) define classification, allowable error, and reporting. Every deliverable should document the datum, basis of bearing, control used, equipment, methods, and the achieved accuracy, so another professional can evaluate and rely on the work.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0014-0000-0000-000000000003', 'acc06b14-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: professional land surveying in Texas is regulated by the Texas Board of Professional Engineers and Land Surveyors (TBPELS). A Registered Professional Land Surveyor (RPLS) must take responsible charge of and seal surveys; the surveyor of record is legally accountable for the work, and TBPELS rules govern boundary procedures, seals, and conduct."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0014-0000-0000-000000000004', 'acc06b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Responsible charge and professional conduct</h3><p>The <strong>surveyor of record</strong> exercises <em>responsible charge</em> — direct control and personal professional judgment — over the survey, even when crews and technicians perform field and office tasks. This means reviewing the work, verifying that it meets the standard, and sealing the deliverable. Ethics, competence within one''s qualifications, and honest reporting of accuracy are not optional add-ons; they are the foundation of the public trust the license represents.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0014-0000-0000-000000000005', 'acc06b14-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Manage scope, schedule, budget, safety, and QA/QC from the start.","Deliverables must meet stated accuracy standards and document datum/basis/methods.","In Texas the RPLS in responsible charge is legally accountable under TBPELS rules."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0015-0000-0000-000000000000', 'acc06b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Pulling it together</h3><p>The final review week consolidates SRVY 2341 into a coherent picture and connects it to the licensure path. In Texas the route to licensure runs through the NCEES <strong>Fundamentals of Surveying (FS)</strong> exam — the basis of the <strong>Surveyor-in-Training (SIT)</strong> credential — followed by the <strong>Principles and Practice of Surveying (PS)</strong> exam and Texas-specific requirements for the <strong>RPLS</strong>. The competencies you built this term — coordinate geometry, horizontal and vertical curves, earthwork, topographic methods, state plane reductions, photogrammetry literacy, and professional practice — map directly onto these exams'' domains.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0015-0000-0000-000000000001', 'acc06b15-0000-0000-0000-000000000001', 'table', '{"headers":["Course topic","Exam relevance"],"rows":[["COGO (forward/inverse, area)","Core computations on FS and PS"],["Horizontal/vertical curves","Route surveying domain"],["Earthwork / cross-sections","Construction surveying"],["State plane / CSF / convergence","Geodesy / mapping domain"],["Professional practice / TBPELS","Texas-specific PS material"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0015-0000-0000-000000000002', 'acc06b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Integrated problem solving</h3><p>Exam problems rarely test one idea in isolation. A typical integrated problem might give grid coordinates for a PI, ask you to reduce a measured ground distance with a combined scale factor, design a curve to fit, compute the PC/PT stations, and then find an area or volume. The skill is recognizing which tool each step needs and carrying consistent units and full precision through the chain. Practice with multi-step problems, not just single-formula drills.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0015-0000-0000-000000000003', 'acc06b15-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Exam-day discipline: (1) write down what is given and what is asked, (2) keep one consistent unit system, (3) carry full calculator precision, (4) sanity-check magnitude, and (5) use independent relationships (deflection = I/2; PT = PC + L; area sign) as built-in checks."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0015-0000-0000-000000000004', 'acc06b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Targeted review</h3><p>Use the midterm and quizzes to find weak spots and drill them. Common high-value review items: converting bearings to azimuths cleanly, the half-angle curve formulas, vertical-curve units (percent and stations), grid-ground direction (which way to divide vs. multiply), and the meaning of convergence. A short, focused review of these recurring traps yields more points than re-reading everything.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0015-0000-0000-000000000005', 'acc06b15-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["This course maps onto the FS/SIT and PS/RPLS exam domains.","Integrated problems chain COGO, curves, areas, and grid-ground reductions.","Win points with unit discipline, full precision, and independent checks."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0016-0000-0000-000000000000', 'acc06b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Final exam — comprehensive scope</h3><p>The Week 16 final covers the entire course. Expect questions spanning coordinate geometry; simple, compound, reverse, and vertical curves; route surveying; earthwork volumes; construction staking; topographic methods and contours; state plane coordinates and grid-ground reduction; introductory photogrammetry and remote sensing; and survey project management and professional practice. Both conceptual and computational questions appear, with several integrated multi-step problems.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0016-0000-0000-000000000001', 'acc06b16-0000-0000-0000-000000000001', 'table', '{"headers":["Domain","Weeks","Representative skill"],"rows":[["Coordinate geometry","1","Forward/inverse, area"],["Horizontal curves","2-4","T, L, stationing, deflections"],["Vertical curves","5-6","Elevations, turning point, K, L"],["Route & earthwork","7, 9","Alignment, end areas, volumes"],["Staking & topo","10-11","Slope stakes, contours, DTM"],["SPCS & photogrammetry","12-13","CSF, convergence, photo scale"],["Professional practice","14","Standards, TBPELS, responsible charge"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0016-0000-0000-000000000002', 'acc06b16-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Final-exam strategy: budget time per point, attempt every problem, show enough work that a partially correct method earns partial credit, and reserve a few minutes to apply unit and magnitude checks before submitting."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0016-0000-0000-000000000003', 'acc06b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>After the course</h3><p>The competencies validated here carry directly into professional field practice in construction and route surveying and into the FS/SIT examination. Keep your problem-solving discipline — consistent units, full precision, and independent checks — as a permanent professional habit. These are the same checks that catch costly errors on real projects.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3410-0016-0000-0000-000000000004', 'acc06b16-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The final is comprehensive across all 15 prior weeks.","Identify the right tool before computing; manage time across problems.","Report in requested units with significant figures and built-in checks."]}'::jsonb, 4);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000001', 'Forward computation', 'Given a starting coordinate, an azimuth, and a distance, compute the coordinate of the next point: N2 = N1 + L cos Az, E2 = E1 + L sin Az.', 'Latitude and departure', 'acc00006-0000-0000-0000-000000000006', 'acc06b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000002', 'Inverse computation', 'Given two coordinates, compute the distance (hypot of the differences) and the azimuth (atan2 of departure over latitude) between them.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000003', 'Coordinate (shoelace) method', 'A method that computes the exact area of a closed polygon from its vertex coordinates as half the absolute value of the cross-product sum.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000004', 'PI (point of intersection)', 'The point where the two tangents of a curve, extended, intersect. The angle there is the intersection angle I, equal to the curve''s central angle.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000005', 'Tangent distance (T)', 'The distance from the PC (or PT) to the PI, equal to R tan(I/2).', 'Half-angle', 'acc00006-0000-0000-0000-000000000006', 'acc06b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000006', 'Degree of curve, arc definition', 'The central angle subtending a 100-ft arc, D = 5729.58/R. Larger degree means a sharper curve.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000007', 'Curve stationing rule', 'PC = PI − T and PT = PC + L. The PT is found by adding arc length to the PC, never by adding T to the PI.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000008', 'Deflection angle', 'The angle turned at the PC from the back tangent to a point on the curve; equal to half the central angle subtending the arc to that point. Total deflection PC to PT is I/2.', 'Inscribed angle', 'acc00006-0000-0000-0000-000000000006', 'acc06b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000009', 'Sub-chord', 'A partial chord shorter than the standard 100-ft chord, used at the start (PC to first even station) and end (last even station to PT) of a curve.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000010', 'Point of compound curvature (PCC)', 'The common point where two same-direction circular arcs of different radii meet on a shared tangent in a compound curve.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000011', 'Point of reverse curvature (PRC)', 'The point where two opposite-direction arcs meet in a reverse curve; the radius changes sense here.', 'Opposite directions', 'acc00006-0000-0000-0000-000000000006', 'acc06b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000012', 'Spiral (transition) curve', 'A clothoid whose radius decreases uniformly from infinity to R, providing gradual curvature change and the length over which superelevation is introduced.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000013', 'Vertical curve', 'An equal-tangent parabola connecting two roadway grades meeting at the PVI, giving a constant rate of grade change.', 'Parabola, not arc', 'acc00006-0000-0000-0000-000000000006', 'acc06b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000014', 'Crest vs. sag curve', 'A crest curve forms a hill (grade decreases, g1>g2); a sag curve forms a valley (grade increases, g1<g2).', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000015', 'Turning point', 'The high or low point of a vertical curve, where the grade is zero, located x = -g1/r stations from the BVC.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000016', 'K value', 'The vertical curve length per one percent of grade change, K = L/A. Minimum K values come from sight-distance design tables by speed and curve type.', 'L over A', 'acc00006-0000-0000-0000-000000000006', 'acc06b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000017', 'Algebraic grade change (A)', 'The absolute difference between the two grades, A = |g2 - g1|, in percent; controls curve length and the mid-curve offset.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000018', 'Mid-curve offset', 'The vertical distance from the grade tangent to the curve at the PVI, equal to A*L/8 (feet, with A in percent and L in stations).', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000019', 'Route surveying', 'The surveying of a linear project (road, pipeline, rail) through reconnaissance, preliminary, location, and construction phases, centered on refining the centerline.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000020', 'Station equation', 'A documented statement (e.g., 45+20 back = 45+00 ahead) reconciling a change in alignment length so downstream stationing stays continuous.', 'Back = ahead', 'acc00006-0000-0000-0000-000000000006', 'acc06b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000021', 'Centerline', 'The master reference line of an alignment, composed of tangents and curves, along which stationing is measured and from which staking offsets are taken.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000022', 'Midterm scope', 'Coordinate geometry, simple horizontal curves and stakeout, compound/reverse curves, and vertical curves (Weeks 1-7).', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000023', 'PT check', 'The point of tangency station must equal PC + L (arc length), and the total deflection PC to PT must equal I/2 — two independent checks on a curve solution.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000024', 'End area', 'The cross-sectional area of cut or fill at a single station, computed by the coordinate method from the ground and template points.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000025', 'Average end area formula', 'Volume = (A1 + A2)/2 times the distance between sections; the standard method for routine earthwork.', 'Trapezoidal in 3D', 'acc00006-0000-0000-0000-000000000006', 'acc06b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000026', 'Mass-haul diagram', 'A plot of cumulative net earthwork versus station used to plan economical haul, identify balance points, and measure haul volume-distance.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000027', 'Slope stake', 'A stake marking the catch point where a designed side slope daylights into existing ground; its offset depends on slope ratio, depth, and ground slope.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000028', 'Catch point (daylight)', 'The point where the design side slope meets existing ground; on level ground its offset from centerline is w + s*h.', 'Side slope meets ground', 'acc00006-0000-0000-0000-000000000006', 'acc06b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000029', 'Blue top', 'A hub driven and marked to the exact finished subgrade elevation, used by the contractor to fine-grade.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000030', 'Digital terrain model (DTM)', 'A 3D model of the ground surface, often stored as a TIN of triangular facets with breaklines, built from surveyed points.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000031', 'Contour interval', 'The constant elevation difference between adjacent contour lines; smaller for flat detailed sites, larger for rugged terrain.', 'Closer = steeper', 'acc00006-0000-0000-0000-000000000006', 'acc06b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000032', 'Breakline', 'A linear feature (ridge, ditch, pavement edge) that constrains TIN triangulation so the surface honors abrupt grade changes.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000033', 'State Plane Coordinate System (Texas)', 'A plane-coordinate system on NAD83 using the Lambert Conformal Conic projection in five Texas zones (North, North Central, Central, South Central, South).', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000034', 'Combined scale factor (CSF)', 'The product of the grid scale factor and the elevation factor; divide a grid distance by CSF to get ground distance, multiply to go the other way.', 'Grid scale * elevation', 'acc00006-0000-0000-0000-000000000006', 'acc06b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000035', 'Convergence (mapping angle)', 'The angle between grid north and geodetic north; grid azimuth = geodetic azimuth - convergence. Positive east of the central meridian.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000036', 'Photo scale', 'The ratio S = f/(H - h) of focal length to the flying height above the ground point; ground distance = photo distance / S.', 'f over (H - h)', 'acc00006-0000-0000-0000-000000000006', 'acc06b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000037', 'Relief displacement', 'The radial outward shift of an elevated point''s image from the principal point on a vertical photo; used to measure object heights and removed by orthorectification.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000038', 'LiDAR', 'An active remote-sensing method that times laser-pulse returns to build dense 3D point clouds, widely used for DTMs and corridor mapping.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000039', 'Responsible charge', 'The direct control and personal professional judgment a licensed surveyor exercises over a survey, required to seal the work.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000040', 'Surveyor of record', 'The licensed professional (in Texas, an RPLS) legally accountable for a survey, who takes responsible charge and seals the deliverable.', 'TBPELS-regulated', 'acc00006-0000-0000-0000-000000000006', 'acc06b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000041', 'Accuracy specification', 'The stated standard (e.g., ALTA/NSPS, NGS/FGDC, agency spec) defining allowable error, classification, and reporting for a survey deliverable.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000042', 'Surveyor-in-Training (SIT)', 'The credential earned by passing the NCEES Fundamentals of Surveying (FS) exam; the first step toward Texas RPLS licensure.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000043', 'Integrated problem', 'An exam problem that chains several competencies (e.g., grid-ground reduction, curve design, stationing, area) requiring consistent units and full precision.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000044', 'Exam check relationships', 'Independent relationships used to verify answers: total deflection = I/2, PT = PC + L, and the sign/magnitude of an area by coordinates.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000045', 'Comprehensive final scope', 'All course domains: COGO, horizontal/vertical curves, route surveying, earthwork, construction staking, topo, SPCS, photogrammetry, and professional practice.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3440-0000-0000-0000-000000000046', 'Partial-credit strategy', 'Show enough method that a correct approach earns credit even if an arithmetic slip changes the final number; attempt every problem.', NULL, 'acc00006-0000-0000-0000-000000000006', 'acc06b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-34']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000001', 'In the inverse computation between two coordinate points, which helper pair correctly gives the distance and azimuth?', 'multiple_choice', '["sin for distance, cos for azimuth","hypot for distance, atan2 for azimuth","tan for distance, asin for azimuth","sqrt for azimuth, atan for distance"]'::jsonb, 'hypot for distance, atan2 for azimuth', 'Distance is the hypotenuse of the latitude and departure (hypot of dN and dE); azimuth is atan2(dE, dN). atan2 resolves the correct quadrant automatically.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b01-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000002', 'Which two quantities completely define a simple horizontal curve?', 'multiple_choice', '["T and L","R and I","E and M","LC and D only"]'::jsonb, 'R and I', 'Given the radius R and the intersection (central) angle I, every other element (T, L, E, M, LC) follows by trigonometry on I/2.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b02-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000003', 'Using the arc definition, a 2-degree curve has approximately what radius?', 'multiple_choice', '["1146 ft","2865 ft","5730 ft","573 ft"]'::jsonb, '2865 ft', 'R = 5729.58 / D = 5729.58 / 2 = 2864.79 ft, i.e., about 2865 ft.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b02-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000004', 'If the PI is at station 24+00, T = 150 ft, and L = 280 ft, what is the PT station?', 'multiple_choice', '["25+30","25+50","22+50","26+80"]'::jsonb, '25+30', 'PC = PI - T = 2400 - 150 = 2250 (22+50). PT = PC + L = 2250 + 280 = 2530, i.e., 25+30. Using PI + T would be the classic blunder.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b03-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000005', 'The point of tangency (PT) station is found by adding the tangent distance T to the PI station.', 'true_false', '["True","False"]'::jsonb, 'False', 'PT = PC + L (arc length). Adding T to the PI overstates the position because the arc is shorter than running out to the PI and back.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b03-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000006', 'Two circular arcs curving in the same direction with different radii, joined on a common tangent, form a:', 'multiple_choice', '["Reverse curve","Compound curve","Spiral curve","Vertical curve"]'::jsonb, 'Compound curve', 'Same direction + different radii + common tangent at a PCC defines a compound curve. Opposite directions would be a reverse curve.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b04-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000007', 'Why are reverse curves without an intervening tangent or spiral discouraged on high-speed highways?', 'multiple_choice', '["They cannot be staked","Superelevation cannot reverse instantaneously at the PRC","They have no PI","Their radius is always too large"]'::jsonb, 'Superelevation cannot reverse instantaneously at the PRC', 'At the PRC the cross-slope (banking) must change sense; without a transition length the superelevation cannot be reversed safely, so a tangent or spiral is provided.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b04-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000008', 'A vertical curve where the incoming grade is +3% and the outgoing grade is -2% is a:', 'multiple_choice', '["Sag curve","Crest curve","Compound curve","Reverse curve"]'::jsonb, 'Crest curve', 'The grade decreases (g1 > g2: +3 to -2), forming a hill, which is a crest curve. A sag has g1 < g2.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b05-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000009', 'A vertical curve has g1 = +2.0% and r = +0.5% per station. At how many stations from the BVC is the low (turning) point? Report stations to 1 decimal.', 'numeric_input', '[]'::jsonb, '4.0', 'x_t = -g1/r = -(2.0)/(0.5)... sign convention: the magnitude is |g1/r| = 2.0/0.5 = 4.0 stations. With g1 positive and r positive this sag''s grade reaches zero 4.0 stations from the BVC.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b05-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000010', 'A crest vertical curve must satisfy a minimum K of 61 with an algebraic grade change A = 5.0%. What minimum curve length L (ft) is required? Report to the nearest foot.', 'numeric_input', '[]'::jsonb, '305', 'L = K*A = 61 * 5.0 = 305 ft.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b06-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000011', 'A station equation such as ''45+20 back = 45+00 ahead'' is used to:', 'multiple_choice', '["Correct a leveling error","Reconcile a change in alignment length so stationing stays continuous","Define a curve''s radius","Set superelevation"]'::jsonb, 'Reconcile a change in alignment length so stationing stays continuous', 'When a revised alignment changes length, a station equation ties back-stationing to ahead-stationing so downstream stations need not be renumbered.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b07-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000012', 'Horizontal and vertical alignments should be designed independently of each other.', 'true_false', '["True","False"]'::jsonb, 'False', 'A route is a 3D object; the two alignments are coordinated so curves, sight distance, drainage, and superelevation work together.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b07-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000013', 'The average-end-area volume between two cross-sections is:', 'multiple_choice', '["(A1 + A2)/2 times the distance","(A1 + A2) times the distance","(A1 - A2)/2 times the distance","d/6 (A1 + 4Am + A2)"]'::jsonb, '(A1 + A2)/2 times the distance', 'Average end area multiplies the mean of the two end areas by the distance between sections. The d/6(A1+4Am+A2) form is the more accurate prismoidal formula.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b09-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000014', 'A slope stake marks the location of the:', 'multiple_choice', '["PVI","Catch (daylight) point where the side slope meets existing ground","Long chord midpoint","Principal point of a photo"]'::jsonb, 'Catch (daylight) point where the side slope meets existing ground', 'The slope stake locates the catch/daylight point; its offset depends on slope ratio, depth, and ground slope.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b10-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000015', 'On level ground, a cut section has template half-width w = 20 ft, side slope 2:1 (s = 2), and cut depth h = 6 ft. What is the catch-point offset from centerline (ft)?', 'numeric_input', '[]'::jsonb, '32', 'offset = w + s*h = 20 + 2*6 = 20 + 12 = 32 ft.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b10-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000016', 'Which statement about contour lines is correct?', 'multiple_choice', '["Contours frequently cross one another","Closely spaced contours indicate steep ground","Contours always form straight lines","Contour interval must increase along a single map"]'::jsonb, 'Closely spaced contours indicate steep ground', 'Contours never cross (except at a vertical cliff) and a constant interval is used on a map; closely spaced contours mean a steep slope.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b11-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000017', 'Texas State Plane zones use which map projection?', 'multiple_choice', '["Transverse Mercator","Lambert Conformal Conic","Oblique Stereographic","Albers Equal Area"]'::jsonb, 'Lambert Conformal Conic', 'Texas''s five SPCS zones use the Lambert Conformal Conic projection, suited to the state''s east-west extent.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b12-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000018', 'A grid distance is 2500.00 ft and the combined scale factor is 0.99988. What is the ground distance (ft)? Report to 2 decimals.', 'numeric_input', '[]'::jsonb, '2500.30', 'Ground = grid / CSF = 2500.00 / 0.99988 = 2500.30 ft.', 'medium', 'acc00006-0000-0000-0000-000000000006', 'acc06b12-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000019', 'On a vertical aerial photograph, photo scale equals:', 'multiple_choice', '["(H - h) / f","f / (H - h)","f * (H - h)","H / f"]'::jsonb, 'f / (H - h)', 'Photo scale S = f/(H - h), the ratio of focal length to flying height above the ground point.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b13-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000020', 'In Texas, an RPLS in responsible charge is legally accountable for a survey and must seal the work under TBPELS rules.', 'true_false', '["True","False"]'::jsonb, 'True', 'The Texas Board of Professional Engineers and Land Surveyors (TBPELS) requires a Registered Professional Land Surveyor in responsible charge to seal the survey, and that surveyor of record is legally accountable.', 'easy', 'acc00006-0000-0000-0000-000000000006', 'acc06b14-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3430-0000-0000-0000-000000000021', 'An exam problem gives grid coordinates for a PI, a measured ground tangent distance, and a combined scale factor, then asks for the PC station. In what order are the tools applied?', 'multiple_choice', '["Find PT first, then reduce grid to ground","Reduce ground distance to grid, then compute curve elements and PC = PI - T","Compute area first, then convergence","Set superelevation, then stationing"]'::jsonb, 'Reduce ground distance to grid, then compute curve elements and PC = PI - T', 'Work in one consistent system: convert distances with the CSF, compute T from R and I, then PC = PI - T. Recognizing the tool for each step is the integrated-problem skill.', 'hard', 'acc00006-0000-0000-0000-000000000006', 'acc06b15-0000-0000-0000-000000000001', ARRAY['buildout','module-34']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3460-0000-0000-0000-000000000001', 'A line has length {{dist:f2}} ft on an azimuth of {{az:f1}} deg from north. Compute the LATITUDE (north-south component, N positive) of the line in feet.', 'numeric_input', '[]'::jsonb, '0', 'Latitude = L cos(Az) = {{dist:f2}} x cos({{az:f1}} deg) = {{_answer}} ft. (Its departure, L sin(Az), would be {{dep:f2}} ft east.)', 'easy', 'acc00006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-34','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3450-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3460-0000-0000-0000-000000000002', 'After summing a traverse, the closure in latitudes is {{clat:f3}} ft and the closure in departures is {{cdep:f3}} ft. Compute the LINEAR MISCLOSURE (the length of the closure vector) in feet.', 'numeric_input', '[]'::jsonb, '0', 'Linear misclosure = sqrt(dLat^2 + dDep^2) = hypot({{clat:f3}}, {{cdep:f3}}) = {{_answer}} ft. This is divided by the traverse perimeter to express the relative precision (1:n).', 'medium', 'acc00006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-34','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3450-0000-0000-0000-000000000002', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3460-0000-0000-0000-000000000003', 'A grid distance is {{grid:f2}} ft. The grid scale factor is {{gsf:f5}} and the elevation factor is {{ef:f5}}. Compute the GROUND distance in feet.', 'numeric_input', '[]'::jsonb, '0', 'CSF = {{gsf:f5}} x {{ef:f5}} = {{csf:f5}}. Ground = grid / CSF = {{grid:f2}} / {{csf:f5}} = {{_answer}} ft. (Multiply to go from ground back to grid.)', 'medium', 'acc00006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-34','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3450-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3460-0000-0000-0000-000000000004', 'A simple horizontal curve has radius R = {{R:f1}} ft and intersection angle I = {{I:f1}} deg. Compute the TANGENT distance T in feet.', 'numeric_input', '[]'::jsonb, '0', 'T = R tan(I/2) = {{R:f1}} x tan({{I:f1}}/2) = {{_answer}} ft. (The arc length L = R*I(rad) = {{L:f2}} ft.)', 'medium', 'acc00006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-34','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3450-0000-0000-0000-000000000004', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3460-0000-0000-0000-000000000005', 'A simple horizontal curve has radius R = {{R:f1}} ft and intersection angle I = {{I:f1}} deg. Compute the ARC LENGTH L in feet.', 'numeric_input', '[]'::jsonb, '0', 'L = R * I(radians) = {{R:f1}} x toRad({{I:f1}}) = {{_answer}} ft. (The tangent T = R tan(I/2) = {{T:f2}} ft.)', 'easy', 'acc00006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-34','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3450-0000-0000-0000-000000000005', 0.05);
