INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3460-0000-0000-0000-000000000006', 'An equal-tangent vertical curve has BVC elevation {{ybvc:f2}} ft, incoming grade g1 = {{g1:f2}} percent, outgoing grade g2 = {{g2:f2}} percent, and total length L = {{Lst:f1}} stations. Compute the curve elevation (ft) at x = {{x:f1}} stations from the BVC.', 'numeric_input', '[]'::jsonb, '0', 'With grades in percent and x in stations, Y = Y_BVC + g1*x + (r/2)x^2 where r = (g2-g1)/L = {{r:f4}}. Substituting gives {{_answer}} ft.', 'hard', 'acc00006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-34','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3450-0000-0000-0000-000000000006', 0.02);
