INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3460-0000-0000-0000-000000000007', 'A triangular parcel has corners A({{na:f1}}, {{ea:f1}}), B({{nb:f1}}, {{eb:f1}}), and C({{nc:f1}}, {{ec:f1}}) as (Northing, Easting) in feet. Compute the AREA in square feet by the coordinate method.', 'numeric_input', '[]'::jsonb, '0', 'The coordinate (shoelace) method gives A = |E_A(N_B-N_C) + E_B(N_C-N_A) + E_C(N_A-N_B)| / 2 = |{{cross:f1}}| / 2 = {{_answer}} sq ft. The sign of the sum reflects only vertex order.', 'medium', 'acc00006-0000-0000-0000-000000000006', NULL, ARRAY['buildout','module-34','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3450-0000-0000-0000-000000000007', 1);
