-- 366_buildout_m34.sql (GENERATED) — fill empty lessons for "ACC SRVY 2341 — Advanced Surveying"
-- Module acc00006-0000-0000-0000-000000000006. Namespaced by tag 'buildout' / created_by 'buildout:m34' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='acc00006-0000-0000-0000-000000000006' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='acc00006-0000-0000-0000-000000000006' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='acc00006-0000-0000-0000-000000000006' AND created_by='buildout:m34';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Coordinate geometry (COGO) reduces every surveying computation to forward and inverse operations on (N,E) points.','The inverse uses hypot for distance and atan2 for azimuth; the forward uses sin and cos of the azimuth.','Area by coordinates is exact for any closed polygon and underlies cross-section and parcel computations.']::text[], learning_objectives=ARRAY['Review rectangular and polar coordinate relationships used throughout route surveying.','Compute inverse (distance and direction) and forward (coordinate) problems from station data.','Apply the coordinate (DMD/shoelace) method for area as the foundation for earthwork and boundary work.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b01-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b01-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A simple curve is a single circular arc joining two tangents that intersect at the PI with deflection angle I.','Tangent T = R tan(I/2) and arc length L = R I (with I in radians) are the two master equations.','Degree of curve (arc definition) is the central angle subtending a 100-ft arc: D = 5729.58/R.']::text[], learning_objectives=ARRAY['Define the geometric elements of a simple horizontal curve (PC, PI, PT, R, I, T, L, E, M, LC).','Compute the tangent, length, external, and middle ordinate from R and I.','Relate degree of curve (arc and chord definition) to radius.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b02-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b02-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['PC station = PI station - T; PT station = PC station + L (never PI + T).','The deflection angle from the back tangent to any curve point is half the subtended arc''s central angle.','Field layout proceeds by occupying the PC and turning deflection angles while taping (or EDM) chord distances.']::text[], learning_objectives=ARRAY['Compute PC and PT stations from the PI station, T, and L.','Lay out a simple curve by the deflection-angle (chord) method.','Compute deflection angles and chord lengths to even stations on the curve.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b03-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b03-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A compound curve is two same-direction arcs of different radii meeting at a PCC on a common tangent.','A reverse curve is two opposite-direction arcs meeting at a PRC; abrupt reversals require a spiral or tangent between them.','Spirals provide a gradual change in curvature so superelevation can be introduced safely at design speed.']::text[], learning_objectives=ARRAY['Distinguish compound, reverse, and spiral curves and state where each is appropriate.','Solve a two-arc compound curve given the common tangent and component radii/angles.','Explain spiral transition curves, superelevation, and why reverse curves need separation.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b04-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b04-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Vertical curves are parabolas connecting two grades; the rate of grade change r = (g2 - g1)/L is constant.','Elevation = BVC elevation + g1*x + (r/2)*x^2, with x measured in stations from the BVC.','The turning point is where the tangent grade reaches zero: x = -g1/r stations from the BVC.']::text[], learning_objectives=ARRAY['Describe a parabolic vertical curve and define crest vs. sag curves.','Compute elevations along an equal-tangent vertical curve from the BVC.','Locate the turning point (high or low point) of a vertical curve.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b05-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b05-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=38, key_takeaways=ARRAY['The K value (L per percent of grade change, K = L/A) packages sight-distance design into one number.','Curve length L = K*A, where A = |g2 - g1| is the algebraic grade change in percent.','Staking a vertical curve means tabulating finished elevations at each even station for grade stakes.']::text[], learning_objectives=ARRAY['Apply sight-distance criteria (K value) to select vertical curve length.','Compute finished-grade elevations at even stations for staking.','Stake a vertical curve and check clearance and drainage at the turning point.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b06-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b06-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Route surveying proceeds reconnaissance to preliminary to location to construction, refining the centerline at each phase.','The horizontal alignment (tangents + curves) and vertical alignment (grades + vertical curves) must be coordinated in 3D.','Station equations reconcile changes in alignment length so continuous stationing is preserved.']::text[], learning_objectives=ARRAY['Outline the phases of route surveying from reconnaissance to final alignment.','Combine horizontal and vertical alignment into a 3D design that meets sight and grade limits.','Explain stationing, equations, and the role of the centerline in route projects.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b07-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b07-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The midterm covers coordinate geometry, simple/compound/reverse curves, and vertical curves.','Bring full-precision through every multi-step curve computation; round only the final answer.','Check answers with independent relationships (e.g., total deflection = I/2; PT check).']::text[], learning_objectives=ARRAY['Review and self-assess horizontal and vertical curve computations covered in Weeks 1-7.','Demonstrate mastery of curve stationing, deflection layout, and parabolic elevation.','Identify weak areas to target before the second half of the course.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b08-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b08-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['End area is the cross-sectional area of cut or fill at a station, found by the coordinate method.','Volume by average end area = (A1 + A2)/2 * distance; the prismoidal formula adds a middle area for accuracy.','A mass-haul diagram cumulates net earthwork to plan economical haul and balance points.']::text[], learning_objectives=ARRAY['Compute cross-section end areas by the coordinate method.','Apply the average-end-area and prismoidal formulas to find earthwork volumes.','Distinguish cut, fill, and the role of shrinkage/swell and mass haul.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b09-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b09-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=38, key_takeaways=ARRAY['Construction staking transfers the design to the ground with offset, slope, and grade stakes.','A slope stake marks the catch point where the design side slope meets existing ground.','Blue tops set finished grade; cut/fill is marked relative to a reference offset stake.']::text[], learning_objectives=ARRAY['Describe offset, slope, and grade staking for construction.','Compute slope-stake catch points from template, slope ratio, and ground.','Explain blue tops, cut/fill marks, and stake marking conventions.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b10-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b10-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Topographic surveys capture 3D ground points that become a DTM/TIN surface for mapping and design.','Contours are interpolated from the surface; they never cross and close on themselves or the map edge.','Contour interval is chosen for terrain relief and map purpose; closer spacing means steeper ground.']::text[], learning_objectives=ARRAY['Compare topographic data-collection methods: total station, RTK GPS, and LiDAR.','Explain DTM/TIN surfaces and how contours are interpolated.','Apply contour rules and select an appropriate contour interval.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b11-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b11-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=42, key_takeaways=ARRAY['Texas uses the Lambert Conformal Conic projection in five SPCS zones on NAD83.','Ground distance = grid distance / combined scale factor (CSF = grid scale factor * elevation factor).','Convergence is the angle between grid north and geodetic north; grid azimuth = geodetic azimuth - convergence.']::text[], learning_objectives=ARRAY['Explain the Texas State Plane Coordinate System (Lambert zones) and NAD83.','Convert between grid and ground distances using the combined scale factor.','Apply convergence to relate grid azimuth and geodetic azimuth.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b12-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b12-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Photogrammetry derives measurements and 3D models from overlapping photographs.','Photo scale = f/(H - h); relief and tilt displace image points from their true map position.','Remote sensing (passive imagery and active LiDAR/radar) extends mapping over large areas.']::text[], learning_objectives=ARRAY['Define photogrammetry and the geometry of a vertical aerial photograph.','Compute photo scale and relate flying height, focal length, and ground coverage.','Contrast photogrammetry with active remote sensing (LiDAR, radar) and their products.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b13-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b13-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A survey project is managed for scope, schedule, budget, safety, and quality with documented QA/QC.','Deliverables are governed by accuracy standards and by the client contract and applicable specifications.','In Texas the RPLS and the surveyor of record bear legal responsibility under TBPELS rules.']::text[], learning_objectives=ARRAY['Outline survey project management: scope, schedule, budget, and QA/QC.','Describe accuracy specifications, deliverables, and standards governing professional work.','Explain the responsibilities of the surveyor of record and TBPELS rules in Texas.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b14-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b14-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=38, key_takeaways=ARRAY['The SIT (FS) and RPLS (PS) exams test the integrated competencies this course develops.','Strong candidates manage units rigorously, keep full precision, and verify with independent checks.','Integrated problems combine curves, coordinates, areas, and grid-ground reductions.']::text[], learning_objectives=ARRAY['Synthesize the full course: COGO, curves, earthwork, control, SPCS, and management.','Map course topics to SIT/RPLS exam domains and practice integrated problems.','Build an exam strategy: units, checks, and time management.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b15-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b15-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The final is comprehensive: COGO, all curves, earthwork, topo, SPCS, photogrammetry, and practice.','Plan time, read each problem fully, and identify the tool before computing.','Report answers in requested units with appropriate significant figures and independent checks.']::text[], learning_objectives=ARRAY['Demonstrate comprehensive mastery across all course topics on the final exam.','Solve integrated multi-step problems under time constraints.','Apply professional judgment to units, accuracy, and reporting.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc06b16-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc06b16-0000-0000-0000-000000000001';
  'eeee3450-0000-0000-0000-000000000001', 'Latitude and departure of a course', 'Latitude and departure of a course', 'Advanced Surveying — Coordinate Geometry', 'Latitude and departure', 'numeric_input', 'easy', 'A line has length {{dist:f2}} ft on an azimuth of {{az:f1}} deg from north. Compute the LATITUDE (north-south component, N positive) of the line in feet.', 'dist*cos(toRad(az))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"az","type":"float","min":20,"max":70,"decimals":1},{"name":"dist","type":"float","min":200,"max":900,"decimals":2}]'::jsonb, '[{"name":"dep","formula":"dist*sin(toRad(az))"}]'::jsonb, '[{"step_number":1,"title":"Latitude formula","formula":"Lat = L cos(Az)","calculation_template":"{{dist:f2}} x cos({{az:f1}} deg)"},{"step_number":2,"title":"Compute","result_template":"Latitude = {{_answer}} ft (north positive)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Latitude = L cos(Az) = {{dist:f2}} x cos({{az:f1}} deg) = {{_answer}} ft. (Its departure, L sin(Az), would be {{dep:f2}} ft east.)', 'acc00006-0000-0000-0000-000000000006', ARRAY['buildout','module-34','practice']::text[], true, 'buildout:m34');
  'eeee3450-0000-0000-0000-000000000002', 'Traverse misclosure by hypot of latitude and departure', 'Traverse misclosure by hypot of latitude and departure', 'Advanced Surveying — Coordinate Geometry', 'Misclosure', 'numeric_input', 'medium', 'After summing a traverse, the closure in latitudes is {{clat:f3}} ft and the closure in departures is {{cdep:f3}} ft. Compute the LINEAR MISCLOSURE (the length of the closure vector) in feet.', 'hypot(clat, cdep)', '{"decimals":3,"unit":"ft","tolerance":0.005}', '[{"name":"clat","type":"float","min":-0.4,"max":0.4,"decimals":3},{"name":"cdep","type":"float","min":-0.4,"max":0.4,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Closure vector","formula":"e = hypot(dLat, dDep)","calculation_template":"hypot({{clat:f3}}, {{cdep:f3}})"},{"step_number":2,"title":"Compute","result_template":"Linear misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Linear misclosure = sqrt(dLat^2 + dDep^2) = hypot({{clat:f3}}, {{cdep:f3}}) = {{_answer}} ft. This is divided by the traverse perimeter to express the relative precision (1:n).', 'acc00006-0000-0000-0000-000000000006', ARRAY['buildout','module-34','practice']::text[], true, 'buildout:m34');
  'eeee3450-0000-0000-0000-000000000003', 'Grid-to-ground distance via combined scale factor', 'Grid-to-ground distance via combined scale factor', 'Advanced Surveying — State Plane', 'Grid and ground', 'numeric_input', 'medium', 'A grid distance is {{grid:f2}} ft. The grid scale factor is {{gsf:f5}} and the elevation factor is {{ef:f5}}. Compute the GROUND distance in feet.', 'grid/(gsf*ef)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"grid","type":"float","min":800,"max":5000,"decimals":2},{"name":"gsf","type":"float","min":0.9999,"max":1.0001,"decimals":5},{"name":"ef","type":"float","min":0.9998,"max":1,"decimals":5}]'::jsonb, '[{"name":"csf","formula":"gsf*ef"}]'::jsonb, '[{"step_number":1,"title":"Combined scale factor","formula":"CSF = GSF x EF","calculation_template":"{{gsf:f5}} x {{ef:f5}} = {{csf:f5}}"},{"step_number":2,"title":"Grid to ground","formula":"ground = grid / CSF","calculation_template":"{{grid:f2}} / {{csf:f5}}"},{"step_number":3,"title":"Compute","result_template":"Ground distance = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'CSF = {{gsf:f5}} x {{ef:f5}} = {{csf:f5}}. Ground = grid / CSF = {{grid:f2}} / {{csf:f5}} = {{_answer}} ft. (Multiply to go from ground back to grid.)', 'acc00006-0000-0000-0000-000000000006', ARRAY['buildout','module-34','practice']::text[], true, 'buildout:m34');
  'eeee3450-0000-0000-0000-000000000004', 'Tangent distance of a simple horizontal curve', 'Tangent distance of a simple horizontal curve', 'Advanced Surveying — Horizontal Curves', 'Curve elements', 'numeric_input', 'medium', 'A simple horizontal curve has radius R = {{R:f1}} ft and intersection angle I = {{I:f1}} deg. Compute the TANGENT distance T in feet.', 'R*tan(toRad(I/2))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"R","type":"float","min":400,"max":1500,"decimals":1},{"name":"I","type":"float","min":20,"max":80,"decimals":1}]'::jsonb, '[{"name":"L","formula":"R*toRad(I)"}]'::jsonb, '[{"step_number":1,"title":"Tangent formula","formula":"T = R tan(I/2)","calculation_template":"{{R:f1}} x tan({{I:f1}}/2 deg)"},{"step_number":2,"title":"Compute","result_template":"T = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'T = R tan(I/2) = {{R:f1}} x tan({{I:f1}}/2) = {{_answer}} ft. (The arc length L = R*I(rad) = {{L:f2}} ft.)', 'acc00006-0000-0000-0000-000000000006', ARRAY['buildout','module-34','practice']::text[], true, 'buildout:m34');
  'eeee3450-0000-0000-0000-000000000005', 'Curve length of a simple horizontal curve', 'Curve length of a simple horizontal curve', 'Advanced Surveying — Horizontal Curves', 'Curve elements', 'numeric_input', 'easy', 'A simple horizontal curve has radius R = {{R:f1}} ft and intersection angle I = {{I:f1}} deg. Compute the ARC LENGTH L in feet.', 'R*toRad(I)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"R","type":"float","min":400,"max":1500,"decimals":1},{"name":"I","type":"float","min":20,"max":80,"decimals":1}]'::jsonb, '[{"name":"T","formula":"R*tan(toRad(I/2))"}]'::jsonb, '[{"step_number":1,"title":"Arc length formula","formula":"L = R I(rad)","calculation_template":"{{R:f1}} x toRad({{I:f1}} deg)"},{"step_number":2,"title":"Compute","result_template":"L = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'L = R * I(radians) = {{R:f1}} x toRad({{I:f1}}) = {{_answer}} ft. (The tangent T = R tan(I/2) = {{T:f2}} ft.)', 'acc00006-0000-0000-0000-000000000006', ARRAY['buildout','module-34','practice']::text[], true, 'buildout:m34');
  'eeee3450-0000-0000-0000-000000000006', 'Vertical curve elevation at an offset station', 'Vertical curve elevation at an offset station', 'Advanced Surveying — Vertical Curves', 'Parabolic elevation', 'numeric_input', 'hard', 'An equal-tangent vertical curve has BVC elevation {{ybvc:f2}} ft, incoming grade g1 = {{g1:f2}} percent, outgoing grade g2 = {{g2:f2}} percent, and total length L = {{Lst:f1}} stations. Compute the curve elevation (ft) at x = {{x:f1}} stations from the BVC.', 'ybvc + g1*x + (((g2-g1)/Lst)/2)*x*x', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"ybvc","type":"float","min":500,"max":900,"decimals":2},{"name":"g1","type":"float","min":1,"max":3.5,"decimals":2},{"name":"g2","type":"float","min":-3.5,"max":-1,"decimals":2},{"name":"Lst","type":"float","min":4,"max":8,"decimals":1},{"name":"x","type":"float","min":1,"max":3,"decimals":1}]'::jsonb, '[{"name":"r","formula":"(g2-g1)/Lst"}]'::jsonb, '[{"step_number":1,"title":"Rate of grade change","formula":"r = (g2 - g1)/L","calculation_template":"({{g2:f2}} - {{g1:f2}}) / {{Lst:f1}} = {{r:f4}} per station"},{"step_number":2,"title":"Parabolic elevation","formula":"Y = Y_BVC + g1 x + (r/2) x^2","calculation_template":"{{ybvc:f2}} + {{g1:f2}}({{x:f1}}) + ({{r:f4}}/2)({{x:f1}})^2"},{"step_number":3,"title":"Compute","result_template":"Elevation = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'With grades in percent and x in stations, Y = Y_BVC + g1*x + (r/2)x^2 where r = (g2-g1)/L = {{r:f4}}. Substituting gives {{_answer}} ft.', 'acc00006-0000-0000-0000-000000000006', ARRAY['buildout','module-34','practice']::text[], true, 'buildout:m34');
  'eeee3450-0000-0000-0000-000000000007', 'Area of a parcel by coordinates (triangle)', 'Area of a parcel by coordinates (triangle)', 'Advanced Surveying — Coordinate Geometry', 'Area by coordinates', 'numeric_input', 'medium', 'A triangular parcel has corners A({{na:f1}}, {{ea:f1}}), B({{nb:f1}}, {{eb:f1}}), and C({{nc:f1}}, {{ec:f1}}) as (Northing, Easting) in feet. Compute the AREA in square feet by the coordinate method.', 'abs(ea*(nb-nc) + eb*(nc-na) + ec*(na-nb))/2', '{"decimals":1,"unit":"sq ft","tolerance":1}', '[{"name":"na","type":"float","min":1000,"max":1100,"decimals":1},{"name":"ea","type":"float","min":1000,"max":1100,"decimals":1},{"name":"nb","type":"float","min":1300,"max":1450,"decimals":1},{"name":"eb","type":"float","min":1000,"max":1100,"decimals":1},{"name":"nc","type":"float","min":1000,"max":1100,"decimals":1},{"name":"ec","type":"float","min":1350,"max":1500,"decimals":1}]'::jsonb, '[{"name":"cross","formula":"ea*(nb-nc) + eb*(nc-na) + ec*(na-nb)"}]'::jsonb, '[{"step_number":1,"title":"Cross-product sum","formula":"Sum = E_A(N_B - N_C) + E_B(N_C - N_A) + E_C(N_A - N_B)","calculation_template":"Sum = {{cross:f1}}"},{"step_number":2,"title":"Half the absolute value","formula":"A = |Sum| / 2","result_template":"Area = {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The coordinate (shoelace) method gives A = |E_A(N_B-N_C) + E_B(N_C-N_A) + E_C(N_A-N_B)| / 2 = |{{cross:f1}}| / 2 = {{_answer}} sq ft. The sign of the sum reflects only vertex order.', 'acc00006-0000-0000-0000-000000000006', ARRAY['buildout','module-34','practice']::text[], true, 'buildout:m34');
COMMIT;
SELECT 'm34 ACC SRVY 2341 — Advanced Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='acc00006-0000-0000-0000-000000000006') || ' blocks.' AS status;